  ('disabled-64311456-moex-00061', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '根據老人福利法之規定，老人之扶養人或其他實際照顧老人之人對老人有 遺棄、妨害自由、傷害或身心虐待等，而情節嚴重，經主管機關對其施以 一定時數之家庭教育及輔導，但卻不接受該教育及輔導或拒不完成其時數 者，會被處以下列多少數額之罰鍰？', '["新臺幣一千二百元以上六千元以下", "新臺幣三千二百元以上六千元以下", "新臺幣二千元以上一萬元以下", "新臺幣三千元以上一萬元以下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
